{
  "description": "This quiz assesses knowledge of HTML5 semantic elements beyond basic tags like <div> and <span>, gauging both conceptual understanding and practical usage. It is positioned as a moderate‑difficulty test with a light‑hearted, encouraging tone that nudges learners to adopt better markup practices. The style mixes humor with a challenge, aiming to motivate developers to improve their HTML skills.",
  "topics": [
    "HTML5 semantic tags (header, nav, article, section, footer, etc.)",
    "Proper use of structural elements",
    "Accessibility considerations in markup",
    "Differences between generic and semantic elements"
  ],
  "audience": "Front‑end developers, web designers, and anyone with basic HTML experience who wants to validate and deepen their understanding of modern, semantic HTML."
}
